{
  "experiment_plan": {
    "what_to_compare": "英国・米国の青少年大規模調査データにおいて、デジタルテクノロジー利用量の高低と幸福感指標の関連を、複数の仕様（共変量セット、アウトカム定義、利用量の尺度化、サブサンプル、モデル形式）で比較する。加えて、可能な範囲で縦断データでは先行する幸福感と後続の利用量、先行する利用量と後続の幸福感をそれぞれ比較する。",
    "what_to_measure": "主要アウトカムは幸福感（例: life satisfaction, depressive symptoms, self-rated well-being）。主要説明変数はデジタルテクノロジー利用量（総利用時間、SNS利用、スマホ利用など）。補助的に、睡眠時間、対面交流時間、学業時間、既存メンタルヘルス、家庭背景、SES、性別、年齢を測定する。縦断データがある場合は、時点間の変化量またはラグ付き変数も測定する。",
    "procedure": "1) 事前に分析仕様の候補を列挙し、仕様曲線分析として全仕様を実行する。2) 横断データでは、利用量と幸福感の関連を共変量調整の強さ別に推定する。3) 縦断データが利用可能な場合は、(a) 先行幸福感→後続利用量、(b) 先行利用量→後続幸福感の両方向を推定する。4) 媒介候補として睡眠・対面交流・学業時間を含む仕様と含まない仕様を比較する。5) 仕様ごとの効果量分布、符号、統計的有意性、頑健性を要約し、各仮説の判定規則に照らして評価する。",
    "identification_assumptions": [
      {
        "id": "IA1",
        "description": "測定誤差が主要変数に対して系統的に一方向へ偏らず、利用量・幸福感の測定が仕様間で比較可能であること。",
        "if_violated": "効果量の符号や大きさが測定法の違いにより人工的に変化し、仮説間の比較が不安定になる。"
      },
      {
        "id": "IA2",
        "description": "観測された共変量セットが、少なくとも主要な交絡候補（家庭背景、既存メンタルヘルス、SES、性別、年齢）を十分に近似していること。",
        "if_violated": "H3の交絡仮説とH1/H2の方向性を分離できず、残差相関を因果的または逆因果的に解釈できない。"
      },
      {
        "id": "IA3",
        "description": "縦断分析を行う場合、先行時点の測定が後続時点の利用量・幸福感を適切に時間順序づけており、逆の時間順序の混入が小さいこと。",
        "if_violated": "H2の逆因果判定が曖昧になり、先行幸福感が後続利用量を予測するかどうかを識別できない。"
      },
      {
        "id": "IA4",
        "description": "サンプル選択や欠測が、利用量と幸福感の関係に対して強い選択バイアスを導入していないこと。",
        "if_violated": "仕様変更による関連の変動が欠測処理や選択の違いに起因し、H3の『見かけの相関』と区別しにくくなる。"
      }
    ],
    "hypothesis_rules": [
      {
        "id": "H1",
        "accept_if": "仕様曲線の多数の仕様で、利用量が多いほど幸福感が低いという負の関連が一貫して観察され、特に睡眠・対面交流・学業時間を含む仕様でも負の関連が維持される。縦断データでは、先行利用量が後続幸福感の低下を予測し、先行幸福感を調整しても負の方向が残る。",
        "reject_if": "十分な共変量調整後に負の関連が消失する、符号が正に転じる、または縦断データで先行利用量が後続幸福感を予測しない。",
        "hold_if": "仕様によって符号や大きさが大きく揺れ、負の関連が一部仕様でのみ現れるが、調整後も完全には消えない。"
      },
      {
        "id": "H2",
        "accept_if": "縦断データで、先行幸福感の低さが後続の利用量増加を予測し、その予測が先行利用量を調整しても残る。横断データでも、幸福感の低い群で利用量が高い傾向が一貫して観察される。",
        "reject_if": "先行幸福感が後続利用量を予測せず、または利用量を調整すると幸福感→利用量の関連が消失する。さらに、利用量→幸福感の方向が一貫して強い場合。",
        "hold_if": "幸福感→利用量の方向が一部仕様で見えるが、効果が小さいか不安定で、利用量→幸福感との優劣が明確でない。"
      },
      {
        "id": "H3",
        "accept_if": "共変量調整を拡張するほど利用量と幸福感の関連が急速に縮小し、家庭背景・既存メンタルヘルス・SES・性別・年齢を含む仕様で関連が弱いか消失する。層別化後も関連が安定して残らない。",
        "reject_if": "共変量を十分に調整しても関連が安定して残り、仕様変更による縮小が小さい。",
        "hold_if": "調整を強めると関連は縮小するが完全には消えず、仕様依存性も中程度にとどまる。"
      }
    ],
    "analysis_forks": [
      "横断分析のみで判定する分岐と、縦断データを用いて時間順序を検証する分岐を分ける。",
      "共変量なし/最小調整/完全調整の3段階で仕様曲線を比較する。",
      "睡眠・対面交流・学業時間を媒介候補として含める仕様と含めない仕様を分ける。",
      "利用量の定義を総利用時間、SNS利用、スマホ利用、娯楽利用などに分けて頑健性を確認する。",
      "幸福感の定義を単一指標と複数指標で分けて比較する。",
      "サブサンプルを年齢層、性別、国別で分けて異質性を確認する。",
      "欠測処理を完全ケース分析、重み付け、代入法で分けて比較する。",
      "線形モデル、順序ロジット、ロバスト回帰などモデル形式を分けて比較する。"
    ]
  }
}
